namespace ContosoUniversity.Tests.Helpers;

/// <summary>
/// Shared test utilities for creating in-memory contexts and test data.
/// </summary>
internal static class TestHelpers
{
    /// <summary>
    /// Creates a new SchoolContext backed by an in-memory database with a unique name.
    /// </summary>
    public static SchoolContext CreateInMemoryContext(string dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Seeds a SchoolContext with a standard set of test data.
    /// </summary>
    public static void SeedTestData(SchoolContext context)
    {
        var department = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1)
        };
        context.Departments.Add(department);

        var courses = new[]
        {
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = 1 }
        };
        context.Courses.AddRange(courses);

        var students = new[]
        {
            new Student
            {
                ID = 1, FirstMidName = "Carson", LastName = "Alexander",
                EnrollmentDate = new DateTime(2010, 9, 1)
            },
            new Student
            {
                ID = 2, FirstMidName = "Meredith", LastName = "Alonso",
                EnrollmentDate = new DateTime(2012, 9, 1)
            },
            new Student
            {
                ID = 3, FirstMidName = "Arturo", LastName = "Anand",
                EnrollmentDate = new DateTime(2013, 9, 1)
            }
        };
        context.Students.AddRange(students);

        var instructors = new[]
        {
            new Instructor
            {
                ID = 10, FirstMidName = "Kim", LastName = "Abercrombie",
                HireDate = new DateTime(1995, 3, 11)
            },
            new Instructor
            {
                ID = 11, FirstMidName = "Fadi", LastName = "Fakhouri",
                HireDate = new DateTime(2002, 7, 6)
            }
        };
        context.Instructors.AddRange(instructors);

        context.Enrollments.Add(new Enrollment
        {
            EnrollmentID = 1,
            StudentID = 1,
            CourseID = 1050,
            Grade = Grade.A
        });

        context.SaveChanges();
    }

    /// <summary>
    /// Drains the static NotificationService queue to prevent test interference.
    /// </summary>
    public static void DrainNotificationQueue()
    {
        using var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }
}

