[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    public void FullName_WithLastAndFirst_ReturnsCommaSeparated()
    {
        // Arrange - use Student as concrete class since Person is abstract
        var person = new Student { LastName = "Smith", FirstMidName = "John" };

        // Act
        var result = person.FullName;

        // Assert
        Assert.AreEqual("Smith, John", result);
    }

    [TestMethod]
    [DataRow("Doe", "Jane", "Doe, Jane")]
    [DataRow("O'Brien", "Patrick", "O'Brien, Patrick")]
    [DataRow("", "", ", ")]
    public void FullName_VariousInputs_ReturnsExpected(string last, string first, string expected)
    {
        var person = new Student { LastName = last, FirstMidName = first };
        Assert.AreEqual(expected, person.FullName);
    }

    [TestMethod]
    public void ID_SetAndGet_ReturnsValue()
    {
        var person = new Student { ID = 42 };
        Assert.AreEqual(42, person.ID);
    }
}

[TestClass]
public sealed class StudentTests
{
    [TestMethod]
    public void Student_InheritsFromPerson()
    {
        var student = new Student();
        Assert.IsInstanceOfType<Person>(student);
    }

    [TestMethod]
    public void EnrollmentDate_SetAndGet_ReturnsValue()
    {
        var date = new DateTime(2023, 9, 1);
        var student = new Student { EnrollmentDate = date };
        Assert.AreEqual(date, student.EnrollmentDate);
    }

    [TestMethod]
    public void Enrollments_SetAndGet_ReturnsCollection()
    {
        var student = new Student
        {
            Enrollments = new List<Enrollment>
            {
                new Enrollment { EnrollmentID = 1, CourseID = 100 },
                new Enrollment { EnrollmentID = 2, CourseID = 200 }
            }
        };

        Assert.AreEqual(2, student.Enrollments.Count);
    }

    [TestMethod]
    public void Student_RequiredFields_Validation()
    {
        var student = new Student { LastName = null, FirstMidName = null };
        var context = new ValidationContext(student);
        var results = new List<ValidationResult>();

        bool isValid = Validator.TryValidateObject(student, context, results, true);

        Assert.IsFalse(isValid);
        Assert.IsTrue(results.Any(r => r.MemberNames.Contains("LastName")));
        Assert.IsTrue(results.Any(r => r.MemberNames.Contains("FirstMidName")));
    }

    [TestMethod]
    public void Student_LastNameTooLong_FailsValidation()
    {
        var student = new Student
        {
            LastName = new string('A', 51),
            FirstMidName = "Test",
            EnrollmentDate = DateTime.Today
        };
        var context = new ValidationContext(student);
        var results = new List<ValidationResult>();

        bool isValid = Validator.TryValidateObject(student, context, results, true);

        Assert.IsFalse(isValid);
        Assert.IsTrue(results.Any(r => r.MemberNames.Contains("LastName")));
    }

    [TestMethod]
    public void Student_ValidData_PassesValidation()
    {
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };
        var context = new ValidationContext(student);
        var results = new List<ValidationResult>();

        bool isValid = Validator.TryValidateObject(student, context, results, true);

        Assert.IsTrue(isValid);
    }
}

