[TestClass]
public sealed class CourseTests
{
    [TestMethod]
    public void Course_Properties_SetAndGetCorrectly()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/images/chem.jpg"
        };

        Assert.AreEqual(1050, course.CourseID);
        Assert.AreEqual("Chemistry", course.Title);
        Assert.AreEqual(3, course.Credits);
        Assert.AreEqual(1, course.DepartmentID);
        Assert.AreEqual("/images/chem.jpg", course.TeachingMaterialImagePath);
    }

    [TestMethod]
    public void Course_NavigationProperties_CanBeSet()
    {
        var dept = new Department { Name = "Engineering" };
        var course = new Course
        {
            Department = dept,
            Enrollments = new List<Enrollment>(),
            CourseAssignments = new List<CourseAssignment>()
        };

        Assert.AreSame(dept, course.Department);
        Assert.AreEqual(0, course.Enrollments.Count);
        Assert.AreEqual(0, course.CourseAssignments.Count);
    }

    [TestMethod]
    [DataRow(0, true, DisplayName = "Credits 0 - valid")]
    [DataRow(3, true, DisplayName = "Credits 3 - valid")]
    [DataRow(5, true, DisplayName = "Credits 5 - valid")]
    [DataRow(6, false, DisplayName = "Credits 6 - invalid")]
    [DataRow(-1, false, DisplayName = "Credits -1 - invalid")]
    public void Course_Credits_RangeValidation(int credits, bool expectedValid)
    {
        var course = new Course
        {
            CourseID = 1,
            Title = "Test",
            Credits = credits,
            DepartmentID = 1
        };
        var context = new ValidationContext(course) { MemberName = "Credits" };
        var results = new List<ValidationResult>();

        bool isValid = Validator.TryValidateProperty(credits, context, results);

        Assert.AreEqual(expectedValid, isValid);
    }

    [TestMethod]
    public void Course_TitleTooShort_FailsValidation()
    {
        var course = new Course
        {
            CourseID = 1,
            Title = "AB", // MinimumLength = 3
            Credits = 3,
            DepartmentID = 1
        };
        var context = new ValidationContext(course) { MemberName = "Title" };
        var results = new List<ValidationResult>();

        bool isValid = Validator.TryValidateProperty(course.Title, context, results);

        Assert.IsFalse(isValid);
    }

    [TestMethod]
    public void Course_TitleTooLong_FailsValidation()
    {
        var course = new Course
        {
            CourseID = 1,
            Title = new string('X', 51), // MaxLength = 50
            Credits = 3,
            DepartmentID = 1
        };
        var context = new ValidationContext(course) { MemberName = "Title" };
        var results = new List<ValidationResult>();

        bool isValid = Validator.TryValidateProperty(course.Title, context, results);

        Assert.IsFalse(isValid);
    }
}

