using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any leftover notifications from other tests (static queue)
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Drain queue after each test
        while (_sut.ReceiveNotification() != null) { }
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_CREATE_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Student", "42", "John Smith", EntityOperation.CREATE, "admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New Student 'John Smith' has been created", notification.Message);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_CREATE_GeneratesIDMessage()
    {
        _sut.SendNotification("Student", "42", null, EntityOperation.CREATE, "admin");

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UPDATE_GeneratesCorrectMessage()
    {
        _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE, "teacher");

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
        Assert.AreEqual("teacher", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_DELETE_GeneratesCorrectMessage()
    {
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "admin");

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("DELETE", notification.Operation);
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_ShortOverload_GeneratesIDMessage()
    {
        _sut.SendNotification("Instructor", "10", EntityOperation.UPDATE);

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor (ID: 10) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        var before = DateTime.Now;
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now;

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
            $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var result = _sut.ReceiveNotification();
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleSends_ReturnsInFIFOOrder()
    {
        _sut.SendNotification("First", "1", EntityOperation.CREATE);
        _sut.SendNotification("Second", "2", EntityOperation.UPDATE);
        _sut.SendNotification("Third", "3", EntityOperation.DELETE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        var third = _sut.ReceiveNotification();

        Assert.AreEqual("First", first.EntityType);
        Assert.AreEqual("Second", second.EntityType);
        Assert.AreEqual("Third", third.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_RemovesFromQueue()
    {
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();

        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
        // If we get here without exception, test passes
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        service.Dispose();
        // If we get here without exception, test passes
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
    {
        _sut.SendNotification("Student", "42", "  ", EntityOperation.CREATE, "admin");

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        // Empty/whitespace display name should fall back to ID format
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithExplicitNullUser_DefaultsToSystem()
    {
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }
}

