+using Microsoft.VisualStudio.TestTools.UnitTesting;
+using System;
+using System.Collections.Generic;
+using System.Linq;
+
+namespace ContosoUniversity.Tests;
+
+[TestClass]
+public sealed class PaginatedListTests
+{
+    [TestMethod]
+    public void Constructor_SetsPageIndex()
+    {
+        var items = new List<string> { "a", "b" };
+        var list = new PaginatedList<string>(items, 10, 2, 5);
+
+        Assert.AreEqual(2, list.PageIndex);
+    }
+
+    [TestMethod]
+    public void Constructor_CalculatesTotalPages_Correctly()
+    {
+        // 10 items, 3 per page = ceil(10/3) = 4 pages
+        var items = new List<string> { "a", "b", "c" };
+        var list = new PaginatedList<string>(items, 10, 1, 3);
+
+        Assert.AreEqual(4, list.TotalPages);
+    }
+
+    [TestMethod]
+    [DataRow(1, 1, DisplayName = "1 item, 1 per page = 1 page")]
+    [DataRow(5, 1, DisplayName = "5 items, 5 per page = 1 page")]
+    [DataRow(6, 2, DisplayName = "6 items, 5 per page = 2 pages")]
+    [DataRow(10, 2, DisplayName = "10 items, 5 per page = 2 pages")]
+    [DataRow(11, 3, DisplayName = "11 items, 5 per page = 3 pages")]
+    public void Constructor_TotalPages_VariousCounts(int count, int expectedPages)
+    {
+        var list = new PaginatedList<int>(new List<int>(), count, 1, 5);
+        Assert.AreEqual(expectedPages, list.TotalPages);
+    }
+
+    [TestMethod]
+    public void Constructor_AddsItemsToList()
+    {
+        var items = new List<string> { "x", "y", "z" };
+        var list = new PaginatedList<string>(items, 3, 1, 3);
+
+        Assert.AreEqual(3, list.Count);
+        Assert.AreEqual("x", list[0]);
+        Assert.AreEqual("y", list[1]);
+        Assert.AreEqual("z", list[2]);
+    }
+
+    [TestMethod]
+    public void Constructor_ZeroItems_SetsTotalPagesToZero()
+    {
+        var list = new PaginatedList<string>(new List<string>(), 0, 1, 10);
+        Assert.AreEqual(0, list.TotalPages);
+    }
+
+    [TestMethod]
+    public void HasPreviousPage_OnFirstPage_ReturnsFalse()
+    {
+        var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);
+        Assert.IsFalse(list.HasPreviousPage);
+    }
+
+    [TestMethod]
+    public void HasPreviousPage_OnSecondPage_ReturnsTrue()
+    {
+        var list = new PaginatedList<int>(new List<int>(), 20, 2, 10);
+        Assert.IsTrue(list.HasPreviousPage);
+    }
+
+    [TestMethod]
+    public void HasPreviousPage_OnThirdPage_ReturnsTrue()
+    {
+        var list = new PaginatedList<int>(new List<int>(), 30, 3, 10);
+        Assert.IsTrue(list.HasPreviousPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_OnLastPage_ReturnsFalse()
+    {
+        // 20 items, 10 per page = 2 pages; on page 2
+        var list = new PaginatedList<int>(new List<int>(), 20, 2, 10);
+        Assert.IsFalse(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_OnFirstPageWithMorePages_ReturnsTrue()
+    {
+        // 20 items, 10 per page = 2 pages; on page 1
+        var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);
+        Assert.IsTrue(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_SinglePage_ReturnsFalse()
+    {
+        var list = new PaginatedList<int>(new List<int>(), 5, 1, 10);
+        Assert.IsFalse(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void Create_ReturnsCorrectPage()
+    {
+        // Create a queryable source with 15 items
+        var source = Enumerable.Range(1, 15).AsQueryable();
+
+        // Get page 2, 5 items per page => items 6-10
+        var result = PaginatedList<int>.Create(source, 2, 5);
+
+        Assert.AreEqual(2, result.PageIndex);
+        Assert.AreEqual(3, result.TotalPages); // ceil(15/5) = 3
+        Assert.AreEqual(5, result.Count);
+        Assert.AreEqual(6, result[0]);
+        Assert.AreEqual(10, result[4]);
+    }
+
+    [TestMethod]
+    public void Create_FirstPage_ReturnsFirstItems()
+    {
+        var source = Enumerable.Range(1, 20).AsQueryable();
+
+        var result = PaginatedList<int>.Create(source, 1, 5);
+
+        Assert.AreEqual(1, result.PageIndex);
+        Assert.AreEqual(4, result.TotalPages);
+        Assert.AreEqual(5, result.Count);
+        Assert.AreEqual(1, result[0]);
+        Assert.AreEqual(5, result[4]);
+    }
+
+    [TestMethod]
+    public void Create_LastPage_ReturnsRemainingItems()
+    {
+        // 12 items, 5 per page = 3 pages; page 3 has 2 items
+        var source = Enumerable.Range(1, 12).AsQueryable();
+
+        var result = PaginatedList<int>.Create(source, 3, 5);
+
+        Assert.AreEqual(3, result.PageIndex);
+        Assert.AreEqual(3, result.TotalPages);
+        Assert.AreEqual(2, result.Count);
+        Assert.AreEqual(11, result[0]);
+        Assert.AreEqual(12, result[1]);
+    }
+
+    [TestMethod]
+    public void Create_EmptySource_ReturnsEmptyList()
+    {
+        var source = Enumerable.Empty<int>().AsQueryable();
+
+        var result = PaginatedList<int>.Create(source, 1, 10);
+
+        Assert.AreEqual(1, result.PageIndex);
+        Assert.AreEqual(0, result.TotalPages);
+        Assert.AreEqual(0, result.Count);
+    }
+}
