using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context;
    private HomeController _controller;

    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new HomeController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelpers.DrainNotificationQueue();
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void About_WithNoStudents_ReturnsViewWithEmptyList()
    {
        var result = _controller.About();

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as System.Collections.Generic.List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void About_WithStudents_ReturnsGroupedEnrollmentData()
    {
        // Arrange - add students with different enrollment dates
        _context.Students.Add(new Student
        {
            FirstMidName = "John", LastName = "Doe",
            EnrollmentDate = new DateTime(2023, 9, 1)
        });
        _context.Students.Add(new Student
        {
            FirstMidName = "Jane", LastName = "Smith",
            EnrollmentDate = new DateTime(2023, 9, 1)
        });
        _context.Students.Add(new Student
        {
            FirstMidName = "Bob", LastName = "Brown",
            EnrollmentDate = new DateTime(2022, 9, 1)
        });
        _context.SaveChanges();

        // Act
        var result = _controller.About();

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as System.Collections.Generic.List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);

        var group2023 = model.Single(g => g.EnrollmentDate == new DateTime(2023, 9, 1));
        Assert.AreEqual(2, group2023.StudentCount);

        var group2022 = model.Single(g => g.EnrollmentDate == new DateTime(2022, 9, 1));
        Assert.AreEqual(1, group2022.StudentCount);
    }

    [TestMethod]
    public void Contact_ReturnsViewResultWithMessage()
    {
        var result = _controller.Contact();

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsViewResult()
    {
        var result = _controller.Error();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Unauthorized_ReturnsViewResultWithMessage()
    {
        var result = _controller.Unauthorized();

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
