    private StudentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelpers.DrainNotificationQueue();
        _controller?.Dispose();
        _context?.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2010, 9, 1) },
            new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2012, 9, 1) },
            new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2013, 9, 1) },
            new Student { ID = 4, FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = new DateTime(2012, 9, 1) },
            new Student { ID = 5, FirstMidName = "Yan", LastName = "Li", EnrollmentDate = new DateTime(2012, 9, 1) }
        );
        _context.SaveChanges();
    }

    // ===== Index Tests =====

    [TestMethod]
    public void Index_NoParameters_ReturnsViewWithStudentsOrderedByLastName()
    {
        SeedStudents();

        var result = _controller.Index(null, null, null, null);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Count > 0);
        // Default sort is by LastName ascending
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchString_FiltersStudentsByLastName()
    {
        SeedStudents();

        var result = _controller.Index(null, null, "Alexander", null);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchString_FiltersStudentsByFirstName()
    {
        SeedStudents();

        var result = _controller.Index(null, null, "Meredith", null);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alonso", model[0].LastName);
    }

    [TestMethod]
    public void Index_SortNameDesc_ReturnsStudentsOrderedByLastNameDescending()
    {
        SeedStudents();

        var result = _controller.Index("name_desc", null, null, null);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Li", model[0].LastName);
    }

    [TestMethod]
    public void Index_SortDate_ReturnsStudentsOrderedByDateAscending()
    {
        SeedStudents();

        var result = _controller.Index("Date", null, null, null);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(new DateTime(2010, 9, 1), model[0].EnrollmentDate);
    }

    [TestMethod]
    public void Index_SortDateDesc_ReturnsStudentsOrderedByDateDescending()
    {
        SeedStudents();

        var result = _controller.Index("date_desc", null, null, null);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(new DateTime(2013, 9, 1), model[0].EnrollmentDate);
    }

    [TestMethod]
    public void Index_WithSearchString_SetsPageTo1()
    {
        SeedStudents();

        var result = _controller.Index(null, null, "Alexander", null);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_NoSearchString_UsesCurrentFilter()
    {
        SeedStudents();

        var result = _controller.Index(null, "Alexander", null, null);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters()
    {
