    // ===== Index Tests =====

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    // ===== GetNotifications Tests =====

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        var result = _controller.GetNotifications();

        Assert.IsNotNull(result);
        var jsonResult = result as JsonResult;
        Assert.IsNotNull(jsonResult);
        // Check that Value is not null and contains success=true
        Assert.IsNotNull(jsonResult.Value);

        // Use dynamic or reflection to check properties
        var value = jsonResult.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));

        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Send some notifications using the shared service
        using var service = new NotificationService();
        service.SendNotification("Student", "1", "John", EntityOperation.CREATE, "admin");
        service.SendNotification("Course", "2", "Chemistry", EntityOperation.UPDATE, "admin");

        var result = _controller.GetNotifications();

        var jsonResult = result as JsonResult;
        Assert.IsNotNull(jsonResult);
        var value = jsonResult.Value;

        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));

        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(2, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        // Send 15 notifications
        using var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE, "admin");
        }

        var result = _controller.GetNotifications();

        var jsonResult = result as JsonResult;
        Assert.IsNotNull(jsonResult);
        var value = jsonResult.Value;

        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(10, countProp.GetValue(value));
    }

