    {
        var result = _controller.MarkAsRead(1);

        var jsonResult = result as JsonResult;
        Assert.IsNotNull(jsonResult);
        var value = jsonResult.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_NonExistentId_ReturnsSuccess()
    {
        // MarkAsRead is a no-op, should succeed regardless of ID
        var result = _controller.MarkAsRead(999);

        var jsonResult = result as JsonResult;
        Assert.IsNotNull(jsonResult);
        var value = jsonResult.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }
}

